script:
frappe.ui.form.on('Sales Order', {
  validate(frm) {
    const sw = frm.doc.selling_warehouse;
    if (!sw) return;

    (frm.doc.items || []).forEach(row => {
      if (row.warehouse && row.warehouse !== sw) {
        frappe.throw(__(
          "Item {0} warehouse ({1}) must match Selling Warehouse ({2})",
          [row.item_code, row.warehouse, sw]
        ));
      }
    });
  }
});

frappe.listview_settings['Process Payment Reconciliation'] = {
    refresh: function(listview) {
        // Add a primary button to open the Control Panel
        listview.page.add_inner_button(__("Reconciliation Control"), function() {
            show_control_panel();
        }).addClass("btn-primary");
    }
};

function show_control_panel() {
    let d = new frappe.ui.Dialog({
        title: 'Payment Reconciliation Controller',
        fields: [
            {
                label: 'Status Dashboard',
                fieldname: 'dashboard_html',
                fieldtype: 'HTML',
                options: '<p>Loading current status...</p>'
            },
            {
                fieldtype: 'Section Break',
                label: 'Scheduler Settings'
            },
            {
                label: 'Scheduler Status (Cron Job)',
                fieldname: 'scheduler_status',
                fieldtype: 'Select',
                options: ['Active', 'Disabled'],
                description: 'Controls the global background job.'
            },
            {
                label: 'Auto Reconcile Checkbox',
                fieldname: 'auto_reconcile',
                fieldtype: 'Check',
                description: 'The global "Auto Reconcile Payments" setting.'
            },
            {
                fieldtype: 'Section Break',
                label: 'Batch Parameters'
            },
            {
                label: 'Queue Size (Max 100)',
                fieldname: 'queue_size',
                fieldtype: 'Int',
                default: 100
            },
            {
                label: 'Trigger Interval (Minutes)',
                fieldname: 'trigger_minutes',
                fieldtype: 'Int',
                default: 59
            },
            {
                label: 'Posting Type',
                fieldname: 'posting_type',
                fieldtype: 'Select',
                options: ['Reconciliation Date', 'Payment', 'Invoice']
            }
        ],
        primary_action_label: 'Update Settings',
        primary_action: function(values) {
            update_settings(d, values);
        }
    });

    // Load initial data
    frappe.call({
        method: 'payment_control_api',
        args: { cmd: 'get_status' },
        callback: function(r) {
            if (r.message && r.message.data) {
                let data = r.message.data;

                // Update Fields
                d.set_value('scheduler_status', data.scheduler_status);
                d.set_value('auto_reconcile', data.auto_reconcile);
                d.set_value('queue_size', data.queue_size);
                d.set_value('trigger_minutes', data.trigger_minutes);
                d.set_value('posting_type', data.posting_type);

                // Update Dashboard HTML
                let status_color = data.scheduler_status === 'Active' ? 'green' : 'red';
                let html = `
                    <div style="padding:10px; border:1px solid #ddd; background-color:#f9f9f9; border-radius:4px;">
                        <div><b>Scheduler:</b> <span style="color:${status_color}; font-weight:bold;">${data.scheduler_status}</span></div>
                        <div><b>Active Background Jobs:</b> ${data.active_jobs}</div>
                        <div style="font-size:11px; color:#666; margin-top:5px;">Last checked: ${new Date().toLocaleTimeString()}</div>
                    </div>
                `;
                d.fields_dict.dashboard_html.$wrapper.html(html);
            }
        }
    });

    d.show();
}

function update_settings(d, values) {
    frappe.call({
        method: 'payment_control_api',
        args: {
            cmd: 'update',
            scheduler_status: values.scheduler_status,
            auto_reconcile: values.auto_reconcile ? 1 : 0,
            queue_size: values.queue_size,
            trigger_minutes: values.trigger_minutes,
            posting_type: values.posting_type
        },
        callback: function(r) {
            if (!r.exc) {
                frappe.msgprint("Settings Updated Successfully!");
                d.hide();
                // Optional: Refresh list to see any changes if relevant
                cur_list.refresh();
            }
        }
    });
}

frappe.ui.form.on("Sales Order", {
    customer: function(frm) {
        if (!frm.doc.customer) return;
        frappe.call({
            method: "lmt_check_customer_block",
            args: { customer: frm.doc.customer },
            callback: function(r) {
                var res = r.message || {};
                if (res.blocked) {
                    frappe.msgprint({
                        title: "⛔ بيع محظور",
                        indicator: "red",
                        message: res.message || "الزبون محظور من البيع"
                    });
                    frm.set_value("customer", "");
                }
            }
        });
    }
});
